          <button
            key={it.id}
            type="button"
            className={'vn-match-tab' + (it.id === intent ? ' active' : '')}
            onClick={() => onIntent(it.id)}
          >
            {it.id === 'investors' && role === 'investor' ? 'Startup' : it.tab}
          </button>
        ))}
      </div>

