/* Matches (list + detail): editorial pass. Reuses tokens + .btn/.card/.chip/.seg
   from styles.css. Radius scale: cards 18px, score tiles 16px, tabs/pills 999px. */

.vn-match-root,
.vn-detail-root {
  max-width: 820px;
  margin: auto;
  padding: clamp(44px, 6vw, 64px) clamp(20px, 5vw, 64px) 120px;
}

.vn-match-eyebrow {
  margin-top: 20px;
}

.vn-match-h1 {
  margin: 14px 0 0;
}

.vn-match-lede {
  margin: 18px 0 0;
}

.vn-match-tabs {
  display: flex;
  gap: 8px;
  margin-top: 28px;
  flex-wrap: wrap;
}

.vn-match-tab {
  padding: 9px 16px;
  border: 1px solid var(--input-border);
  border-radius: 999px;
  background: var(--card);
  color: var(--text);
  font-family: var(--font-ui);
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  transition: border-color 0.15s, background 0.15s, color 0.15s;
}

.vn-match-tab:hover {
  border-color: var(--input-border-hover);
  background: var(--input-bg);
}

.vn-match-tab:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

.vn-match-tab.active {
  border-color: var(--accent);
  background: var(--accent-soft);
  color: var(--accent);
  font-weight: 600;
}

/* ── Filters (type / sector chips over the loaded list) ── */
.vn-match-filters {
  display: flex;
  flex-direction: column;
  gap: 8px;
  margin-top: 22px;
}

.vn-match-filter-group {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 6px;
}

.vn-match-filter-label {
  min-width: 48px;
  color: var(--muted);
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.vn-match-filter-chip {
  padding: 5px 13px;
  border: 1px solid var(--input-border);
  border-radius: 999px;
  background: transparent;
  color: var(--text);
  font-family: var(--font-ui);
  font-size: 12.5px;
  font-weight: 500;
  cursor: pointer;
  transition: border-color 0.15s, background 0.15s, color 0.15s;
}

.vn-match-filter-chip:hover {
  border-color: var(--input-border-hover);
  background: var(--input-bg);
}

.vn-match-filter-chip:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

.vn-match-filter-chip.active {
  border-color: var(--accent);
  background: var(--accent-soft);
  color: var(--accent);
  font-weight: 600;
}

.vn-match-count-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  margin-top: 26px;
}

.vn-match-count {
  color: var(--text);
  font-size: 13.5px;
}

.vn-match-seg {
  padding: 4px;
  border-radius: 11px;
  gap: 4px;
}

/* ── States (unavailable / error / empty) ──
   Informational, not elevated: hairline border + paper fill, not a shadowed card. */
.vn-match-state {
  margin-top: 22px;
  padding: 32px 28px;
  border: 1px solid var(--border-soft);
  border-radius: 16px;
  background: var(--input-bg);
  text-align: center;
}

.vn-match-state-title {
  margin: 0 0 6px;
  color: var(--err-deep);
  font: 600 14.5px var(--font-ui);
}

.vn-match-state-text {
  margin: 0 auto;
  max-width: 46ch;
  color: var(--text);
  font-size: 14px;
  line-height: 1.6;
}

.vn-match-state .btn {
  margin-top: 18px;
}

.vn-match-state-error {
  background: var(--err-bg-2);
  border-color: var(--err-border);
}

.vn-match-state-error .vn-match-state-text {
  color: var(--err-soft);
}

/* ── Loading skeleton (mirrors the real list shape, no spinner) ── */
.vn-match-loading {
  margin-top: 22px;
}

.vn-match-loading-label {
  display: block;
  margin-bottom: 14px;
  color: var(--text);
  font-size: 13.5px;
}

.vn-match-skeleton {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.vn-match-skel-card {
  display: grid;
  grid-template-columns: 40px 56px 1fr auto;
  gap: 18px;
  align-items: center;
  padding: 20px 22px;
  border: 1px solid var(--border-soft);
  border-radius: 18px;
  background: var(--card);
  box-shadow: var(--shadow-card);
}

/* .vn-skel base + pulse now live in styles.css (shared primitive) */
.vn-skel-rank {
  width: 20px;
  height: 10px;
}

.vn-skel-score {
  width: 52px;
  height: 52px;
  border-radius: 16px;
}

.vn-match-skel-body {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.vn-skel-line {
  height: 9px;
}

.vn-skel-type {
  width: 30%;
}

.vn-skel-name {
  width: 55%;
  height: 12px;
}

.vn-skel-rationale {
  width: 90%;
}

/* ── Match list ── */
.vn-match-list {
  margin-top: 20px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.vn-match-card {
  display: grid;
  grid-template-columns: 40px 56px 1fr auto;
  gap: 18px;
  align-items: center;
  padding: 20px 22px;
  border: 1px solid var(--border);
  border-radius: 18px;
  background: var(--card);
  cursor: pointer;
  box-shadow: var(--shadow-card);
  transition: border-color 0.15s, box-shadow 0.15s, transform 0.15s;
}

.vn-match-card:hover {
  border-color: var(--input-border-hover);
  box-shadow: 0 16px 32px -20px rgba(24, 40, 32, 0.24);
  transform: translateY(-1px);
}

.vn-match-card:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

.vn-match-rank {
  color: var(--dim);
  font: 600 13px var(--font-ui);
}

.vn-match-score {
  display: grid;
  place-items: center;
  width: 52px;
  height: 52px;
  border-radius: 16px;
  background: var(--accent-soft);
  color: var(--accent);
  font: 500 20px var(--font-serif);
  letter-spacing: -0.01em;
}

.vn-match-type {
  display: flex;
  align-items: center;
  gap: 8px;
  color: var(--muted);
  font-size: 11px;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.vn-match-name {
  margin: 6px 0 4px;
  font: 400 20px var(--font-serif);
  letter-spacing: -0.01em;
  color: var(--heading);
}

.vn-match-rationale {
  margin: 0;
  color: var(--text);
  font-size: 13.5px;
  line-height: 1.5;
}

.vn-match-analysis {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  color: var(--accent);
  font-size: 13px;
  font-weight: 600;
  white-space: nowrap;
}

.vn-match-analysis-arrow {
  display: inline-block;
  transition: transform 0.18s cubic-bezier(0.16, 1, 0.3, 1);
}

.vn-match-card:hover .vn-match-analysis-arrow {
  transform: translateX(3px);
}

/* ── Detail ── */

.vn-detail-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 24px;
  margin-top: 22px;
}

.vn-detail-type {
  display: flex;
  align-items: center;
  gap: 8px;
  color: var(--muted);
  font-size: 11px;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

.vn-detail-name {
  margin: 10px 0 0;
}

.vn-detail-sectors {
  display: flex;
  flex-wrap: wrap;
  gap: 7px;
  margin-top: 14px;
}

.vn-detail-sector-chip {
  cursor: default;
}

.vn-detail-score-wrap {
  text-align: center;
  flex: none;
}

.vn-detail-score {
  display: grid;
  place-items: center;
  width: 84px;
  height: 84px;
  border-radius: 16px;
  background: var(--accent-soft);
  color: var(--accent);
  font: 500 34px var(--font-serif);
  letter-spacing: -0.01em;
}

.vn-detail-score-caption {
  margin-top: 8px;
  color: var(--dim);
  font-size: 10px;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.vn-detail-section {
  margin-top: 16px;
}

.vn-detail-rationale {
  margin: 12px 0 0;
  font: 400 19px/1.55 var(--font-serif);
  color: var(--ink-2);
}

.vn-detail-breakdown-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  margin-bottom: 18px;
}

.vn-detail-breakdown-meta {
  color: var(--dim);
  font-size: 12px;
}

.vn-detail-bar-row {
  display: grid;
  grid-template-columns: 130px 1fr 38px;
  gap: 14px;
  align-items: center;
  margin: 11px 0;
}

.vn-detail-bar-label {
  font-size: 13px;
  color: var(--body);
}

.vn-detail-bar-track {
  height: 7px;
  border-radius: 4px;
  background: var(--border-soft);
  overflow: hidden;
}

.vn-detail-bar-fill {
  display: block;
  height: 100%;
  background: var(--accent);
}

.vn-detail-bar-val {
  text-align: right;
  font-size: 13px;
  color: var(--ink-2);
}

/* Match signals / Key facts: hairline-divided, not boxed. These are plain
   fact lists, not artifacts that need to earn a card's elevation. */
.vn-detail-flat {
  padding: 24px 0 6px;
  border-top: 1px solid var(--border-soft);
}

.vn-detail-facts-label {
  margin-bottom: 14px;
}

.vn-detail-facts {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px 24px;
}

.vn-detail-fact {
  font-size: 13.5px;
  line-height: 1.5;
  color: var(--label);
}

.vn-detail-draft-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  margin-bottom: 16px;
}

.vn-detail-lang-seg {
  padding: 3px;
  gap: 4px;
  background: var(--input-bg);
}

.vn-detail-draft-box {
  padding: 20px;
  border: 1px solid var(--border-soft);
  border-radius: 12px;
  background: var(--input-bg);
  white-space: pre-wrap;
  color: var(--label);
  font-size: 14px;
  line-height: 1.62;
}

.vn-detail-copy-row {
  display: flex;
  justify-content: flex-end;
  margin-top: 12px;
}

.vn-detail-copy-btn {
  padding: 9px 15px;
  font-size: 13px;
}

@media (max-width: 720px) {
  .vn-detail-header {
    flex-direction: column;
  }

  .vn-detail-facts {
    grid-template-columns: 1fr;
  }

  .vn-match-skel-card {
    grid-template-columns: 40px 56px 1fr;
  }
}

@media (prefers-reduced-motion: reduce) {
  .vn-match-card,
  .vn-match-tab,
  .vn-match-analysis-arrow {
    transition: none;
  }

  .vn-skel {
    animation: none;
    opacity: 0.7;
  }
}

